1	const BASE_PREMIUMS: Record<string, number> = {
2	  sword: 100,
3	  amulet: 60,
4	  staff: 80,
5	  potion: 40,
6	  rune: 25,
7	  moonstone: 25,
8	};
9	
10	const PROCESSING_FEE = 5;
11	const INITIAL_ASSESSMENT_MULTIPLIER = 1.1;
12	const ALIKE_BUNDLE_DISCOUNT = 15;
13	const CURSED_SURCHARGE_MULTIPLIER = 1.5;
14	const COMPONENT_TYPES = ["rune", "moonstone"];
15	
16	function ceilToWholeGold(amount: number): number {
17	  return Math.ceil(Math.round(amount * 1e6) / 1e6);
18	}
19	
20	function basePremiumFor(itemType: string): number {
21	  return BASE_PREMIUMS[itemType] ?? 0;
22	}
23	
24	function itemPremium(item: { type: string; cursed?: boolean }): number {
25	  const base = basePremiumFor(item.type);
26	  return item.cursed ? base * CURSED_SURCHARGE_MULTIPLIER : base;
27	}
28	
29	function countOfType(items: Array<{ type: string }>, itemType: string): number {
30	  return items.filter((item) => item.type === itemType).length;
31	}
32	
33	function alikeBundleDiscount(items: Array<{ type: string }>): number {
34	  const bundleCount = COMPONENT_TYPES
35	    .reduce((sum, componentType) => sum + Math.floor(countOfType(items, componentType) / 3), 0);
36	  return bundleCount * ALIKE_BUNDLE_DISCOUNT;
37	}
38	
39	export function quote(input: { items: Array<{ type: string; cursed?: boolean }> }): number {
40	  const itemPremiumSum = input.items.reduce((sum, item) => sum + itemPremium(item), 0);
41	  const itemsTotal = itemPremiumSum - alikeBundleDiscount(input.items);
42	  const total = itemsTotal * INITIAL_ASSESSMENT_MULTIPLIER + PROCESSING_FEE;
43	  return ceilToWholeGold(total);
44	}
45	
46	export function claim(_input: unknown): number {
47	  return undefined as unknown as number;
48	}
